import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        List<List<long[]>> graph = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long cost = edge[2];
            if (online[u] && online[v]) {
                graph.get(u).add(new long[]{v, cost});
            }
        }

        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(b[1], a[1]));
        long[] maxMin = new long[n];
        Arrays.fill(maxMin, -1);
        pq.offer(new long[]{0, Long.MAX_VALUE, 0});
        maxMin[0] = Long.MAX_VALUE;

        long result = -1;

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            int node = (int) current[0];
            long currentMin = current[1];
            long totalCost = current[2];

            if (node == n - 1) {
                if (totalCost <= k) {
                    result = Math.max(result, currentMin);
                }
                continue;
            }

            if (currentMin < maxMin[node]) {
                continue;
            }

            for (long[] neighbor : graph.get(node)) {
                int nextNode = (int) neighbor[0];
                long edgeCost = neighbor[1];
                long newTotalCost = totalCost + edgeCost;
                long newMin = Math.min(currentMin, edgeCost);

                if (newTotalCost <= k && newMin > maxMin[nextNode]) {
                    maxMin[nextNode] = newMin;
                    pq.offer(new long[]{nextNode, newMin, newTotalCost});
                }
            }
        }

        return result == -1 ? -1 : result;
    }
}
