private static boolean hasValidPath(List<List<long[]>> graph, boolean[] online, long minCost, long k, int n) {
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[1], b[1]));
    long[] dist = new long[n];
