public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        Map<Integer, List<int[]>> graph = new HashMap<>();
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int cost = (int) edge[2];
            if (!graph.containsKey(u)) {
                graph.put(u, new ArrayList<>());
            }
            graph.get(u).add(new int[]{v, cost});
