        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(b[1], a[1])); // max-heap based on min edge cost
        pq.offer(new long[]{0, Long.MAX_VALUE, 0}); // node, current min edge cost, total cost

        long maxScore = -1;

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            int node = (int) current[0];
            long currentMin = current[1];
            long totalCost = current[2];

            if (node == n - 1) {
                if (totalCost <= k) {
                    maxScore = Math.max(maxScore, currentMin);
                }
                continue;
            }

            if (!graph.containsKey(node)) {
                continue;
            }

            for (int[] neighbor : graph.get(node)) {
                int nextNode = neighbor[0];
