import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        List<List<long[]>> graph = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long cost = edge[2];
            graph.get(u).add(new long[]{v, cost});
        }

        long left = 0;
        long right = (long) 1e18;
        long result = -1;

        while (left <= right) {
            long mid = left + (right - left) / 2;
            if (hasValidPath(graph, online, k, mid, n)) {
                result = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return result;
    }

    private static boolean hasValidPath(List<List<long[]>> graph, boolean[] online, long k, long minCost, int n) {
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[1], b[1]));
        long[] dist = new long[n];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[0] = 0;
        pq.offer(new long[]{0, 0});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            int u = (int) current[0];
            long currentDist = current[1];

            if (u == n - 1) {
                return currentDist <= k;
            }

            if (currentDist > dist[u]) {
                continue;
            }

            for (long[] neighbor : graph.get(u)) {
                int v = (int) neighbor[0];
                long cost = neighbor[1];

                if (!online[v] && v != n - 1) {
                    continue;
                }

                if (cost < minCost) {
                    continue;
                }

                if (dist[v] > currentDist + cost) {
                    dist[v] = currentDist + cost;
                    pq.offer(new long[]{v, dist[v]});
                }
            }
        }

        return false;
    }
}
