        pq.offer(new long[]{0, Long.MAX_VALUE});
        maxMin[0] = Long.MAX_VALUE;

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            int node = (int) current[0];
            long currentMin = current[1];
            if (node == n - 1) {
                continue;
            }
            if (currentMin < maxMin[node]) {
                continue;
            }
            for (long[] neighbor : graph.get(node)) {
                int next = (int) neighbor[0];
                long cost = neighbor[1];
                long newMin = Math.min(currentMin, cost);
